INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('59931bdd-210e-4b1a-9b53-159d9f92933e', 'user_test_123456', '仙草芋圆', '一道经典的夏日消暑甜品，由Q弹的芋圆和滑嫩的仙草组成，搭配清凉的牛奶或椰汁，口感层次丰富。', 'recipes/3bccdcf7-2af6-4b27-8468-9fd91c21bcff-xiancao_yuyuan_1773001399834.png', '蒸锅, 煮锅', '甜点', 'medium', 30, 10, '["甜品","中式","下午茶","消暑"]', '2025-12-05 03:31:32', '2025-12-05 03:31:32');
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('3896dc22-e0f6-4b29-b032-afd076c19292', '59931bdd-210e-4b1a-9b53-159d9f92933e', '仙草冻', 200, '克', 0);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('83cd3aeb-1bd8-49c6-a146-bb7dc1212230', '59931bdd-210e-4b1a-9b53-159d9f92933e', '红薯/芋头', 300, '克', 1);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('3de098ca-fc0a-44cc-8367-eda5c8105075', '59931bdd-210e-4b1a-9b53-159d9f92933e', '木薯淀粉', 150, '克', 2);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('c6a04b16-e7c8-4f75-8d4b-0e1c8a65de76', '59931bdd-210e-4b1a-9b53-159d9f92933e', '细砂糖', 30, '克', 3);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('b22bc4d5-ce34-4b18-8400-da5637a8c236', '59931bdd-210e-4b1a-9b53-159d9f92933e', '牛奶或椰汁', 150, '毫升', 4);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('1bd0e5fe-b16d-4103-b785-9df190da6752', '59931bdd-210e-4b1a-9b53-159d9f92933e', '将红薯和芋头去皮切块，放入蒸锅蒸熟至软烂。', 'prep', 20, 0);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('c5a6e8d2-d00b-4c42-b802-21a5d10b902a', '59931bdd-210e-4b1a-9b53-159d9f92933e', '趁热将蒸好的红薯和芋头压成泥，分别加入木薯淀粉和糖，揉成不粘手的面团。', 'prep', 10, 1);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('4f7351b9-8e8a-413b-b46d-68b85781f0bf', '59931bdd-210e-4b1a-9b53-159d9f92933e', '将面团搓成长条，切成小丁，制成芋圆生坯。', 'prep', 5, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('2f342b62-08b8-44b2-b868-7921c72cebd9', '59931bdd-210e-4b1a-9b53-159d9f92933e', '锅中水烧开，放入芋圆煮至全部浮起，继续煮1-2分钟后捞出，放入冰水中过凉。', 'active_cook', 5, 3);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('1271621b-452b-4c80-84b2-b49e6ffb40b8', '59931bdd-210e-4b1a-9b53-159d9f92933e', '在碗中放入切块的仙草冻和煮好的芋圆，倒入冰镇的牛奶或椰汁即可食用。', 'active_cook', 2, 4);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('2f2680d8-8dee-4ade-9045-dd147fdd6c88', 'user_test_123456', '回锅肉', '回锅肉是一道著名的四川传统菜肴，以其色泽红亮、肥而不腻、口味香浓而闻名。其特点是肉片先煮后炒，故名“回锅”。', 'recipes/e0a5343d-f5cf-45e4-ac75-ff9ab5b306e1-huiguo_rou_1773001412256.png', '炒锅', '午餐/晚餐', 'medium', 15, 20, '["中餐","川菜","猪肉","经典"]', '2026-02-17 00:32:23', '2026-02-17 00:32:23');
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('37874d43-6625-4fa0-9832-0481e5723382', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '五花肉', 400, '克', 0);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('416d7742-dbbd-404d-90a7-1177c329fc27', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '青蒜 (蒜苗)', 100, '克', 1);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('51acd66a-2521-47c1-87eb-2703238cacac', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '郫县豆瓣酱', 1, '汤匙', 2);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('0a5ca02a-6bb8-45b8-97b9-76811c15b78b', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '生姜', 10, '克', 3);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('75db0f84-9a1b-43be-ac48-895dd09b18f0', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '大蒜', 2, '瓣', 4);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('ded8dc6f-039e-47bc-8ab5-ca8745f7d70f', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '料酒', 1, '汤匙', 5);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('bb2c15bf-ff67-4c61-8a3c-8dca076223da', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '白糖', 5, '克', 6);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('2fca65a6-3ffb-4685-a012-c8b2388fb100', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '食用油', 10, '毫升', 7);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('b847f804-f00b-4218-9051-2dacb47651b9', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '将五花肉放入冷水锅中，加入姜片和料酒，煮至八成熟（约15分钟），捞出晾凉。', 'active_cook', 15, 0);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('eb1d147f-38ae-4c1c-b744-430f16754641', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '将煮好的五花肉切成薄片；青蒜斜切成段；姜蒜切片。', 'prep', 5, 1);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('76a6cc0c-f3a3-45b2-8567-3e7981973a5a', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '锅中倒少量油，放入五花肉片中小火煸炒至肉片出油并呈“灯盏窝”状（微卷）。', 'active_cook', 5, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('45e54d2e-6aaa-4d3c-ad6d-9b6737c45d17', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '加入豆瓣酱、姜蒜片翻炒出红油，加入少许糖提鲜。', 'active_cook', 2, 3);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('ef4bd33c-7c44-4943-88fa-67d18aed1624', '2f2680d8-8dee-4ade-9045-dd147fdd6c88', '放入青蒜段，快速大火翻炒至青蒜断生即可出锅。', 'active_cook', 2, 4);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('a11c2bef-bcda-4638-9a35-239cc830ed1b', 'user_test_123456', '白切鸡', '白切鸡又称白斩鸡，是粤菜中最普通的一种。制作简便，不加配料且保持原味，皮爽肉滑，清淡鲜美。', 'recipes/81ef9bc4-8eee-4c10-8388-abb43f51fd91-baiqie_ji_1773001424874.png', '汤锅、菜刀、砧板', '晚餐', 'medium', 15, 25, '["中餐","粤菜","经典","鸡肉"]', '2025-10-13 03:52:36', '2025-10-13 03:52:36');
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('e1fe2865-8f63-4983-b89e-b4fe414a5165', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '三黄鸡', 1000, '克', 0);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('71f73aa9-3ce5-495b-b5c6-57c8a98973b9', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '姜', 30, '克', 1);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('687858c3-00d2-48c0-bd33-6f43ded1e3c9', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '葱', 20, '克', 2);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('bd783992-aec5-44da-b107-705c16b51e67', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '料酒', 15, '毫升', 3);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('b7acabb0-2ab8-4ba6-ad0b-67b708b1f920', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '盐', 5, '克', 4);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('c3797dd9-fc13-4c5b-a003-ad86bee89955', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '花生油', 10, '毫升', 5);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('b53341e7-c94d-465c-b6ac-732031bf82a2', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '将鸡清洗干净，去掉内脏，姜切片，葱打结。', 'prep', 5, 0);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('2b8e22c5-350c-4fe3-822a-57e561c1bcc7', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '锅中加入足量冷水，放入姜片、葱结和料酒，大火烧开。', 'active_cook', 5, 1);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('21611630-fbd9-4d01-8028-161d844fd337', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '提住鸡头，将鸡身放入沸水中烫5秒后提起，重复三次，以使腹腔受热均匀。', 'active_cook', 2, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('1763cd0b-227c-40dc-a1cb-1480f2eac38a', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '将鸡完全浸没在锅中，转小火保持水微开状态，盖上锅盖浸煮约15-20分钟。', 'active_cook', 18, 3);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('a00ea8e6-8c5f-48a2-b4c5-a1e759e372c8', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '将煮熟的鸡取出，立即放入准备好的冰水中浸泡5分钟，使皮质爽脆。', 'prep', 5, 4);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('a81047f7-5ffa-4128-9cf0-679c45deb8e3', 'a11c2bef-bcda-4638-9a35-239cc830ed1b', '捞出沥干水分，在鸡皮表面刷上一层花生油，斩件装盘，搭配姜葱油蘸料食用。', 'prep', 5, 5);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('b09378c1-4634-48f0-a6d7-fe4494998225', 'user_test_123456', '生煎包', '生煎包是流行于上海、江苏及浙江的一种传统小吃。底酥、皮薄、肉香。咬一口满嘴汤汁，口感层次丰富。', 'recipes/f0f0f731-9ab1-4a74-a45d-70813f949c38-shengjian_bao_1773001439109.png', '平底锅, 擀面杖', '中式点心 / 早餐', 'medium', 60, 20, '["中餐","猪肉","点心","面食"]', '2026-02-15 07:52:33', '2026-02-15 07:52:33');
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('9ad407b8-9ef0-4a9d-8403-c21c2ec82c16', 'b09378c1-4634-48f0-a6d7-fe4494998225', '中筋面粉', 300, '克', 0);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('33fcb1c0-cb0f-4421-92ce-40a810171a47', 'b09378c1-4634-48f0-a6d7-fe4494998225', '温水', 160, '克', 1);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('3b50cde5-7b47-49ff-a70c-8b5894fe655b', 'b09378c1-4634-48f0-a6d7-fe4494998225', '干酵母', 3, '克', 2);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('742f9036-7265-4167-aaca-f45939ebfc71', 'b09378c1-4634-48f0-a6d7-fe4494998225', '猪肉馅', 300, '克', 3);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('4ba71cd3-ccee-43a2-8b06-27991ed681ea', 'b09378c1-4634-48f0-a6d7-fe4494998225', '皮冻', 100, '克', 4);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('281a54b5-dec8-4d24-9dfc-d2b212fae718', 'b09378c1-4634-48f0-a6d7-fe4494998225', '生抽', 15, '克', 5);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('ff3657ef-08e0-4d00-85cc-f475983aff38', 'b09378c1-4634-48f0-a6d7-fe4494998225', '老抽', 5, '克', 6);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('8e596d1e-0a46-47f9-9a7d-bcb22b0b7646', 'b09378c1-4634-48f0-a6d7-fe4494998225', '盐', 3, '克', 7);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('6679e055-fdce-44d8-86a9-4e423b89ac75', 'b09378c1-4634-48f0-a6d7-fe4494998225', '糖', 10, '克', 8);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('2099a88d-9861-4109-87d9-03118e76f9f1', 'b09378c1-4634-48f0-a6d7-fe4494998225', '葱花', 20, '克', 9);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('226caa8b-5861-440b-a858-7c19c3023e0e', 'b09378c1-4634-48f0-a6d7-fe4494998225', '姜末', 10, '克', 10);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('35120454-0319-4253-83d9-1cb007b43ed5', 'b09378c1-4634-48f0-a6d7-fe4494998225', '黑芝麻', 5, '克', 11);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('6da3cf80-990d-4fa6-998e-dea8ea8004c7', 'b09378c1-4634-48f0-a6d7-fe4494998225', '食用油', 30, '克', 12);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('bb5052da-021b-4a58-8aa1-dc001db2fd4f', 'b09378c1-4634-48f0-a6d7-fe4494998225', '面粉加入酵母和温水，揉成光滑面团，盖上保鲜膜发酵至两倍大。', 'prep', 45, 0);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('d285255d-d455-4356-b96d-e936a329dd14', 'b09378c1-4634-48f0-a6d7-fe4494998225', '将猪肉馅加入生抽、老抽、盐、糖、姜末、葱花顺时针搅拌上劲，最后混入切碎的皮冻。', 'prep', 15, 1);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('d8e45169-1d72-4182-88ee-aa9df46776dc', 'b09378c1-4634-48f0-a6d7-fe4494998225', '发酵好的面团排气，分成小剂子，包入肉馅，收口朝下放置。', 'prep', 20, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('64c29bf6-109b-468d-8ed8-ad46c3e6a0e0', 'b09378c1-4634-48f0-a6d7-fe4494998225', '平底锅倒入少量油，放入包子，中火煎至底部金黄。', 'active_cook', 5, 3);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('3ade81d3-1b38-4b95-8c5e-719a8b5be0a4', 'b09378c1-4634-48f0-a6d7-fe4494998225', '倒入没过包子三分之一的水，盖上锅盖焖煮约10分钟直至水分收干。', 'active_cook', 10, 4);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('af1b4a53-2b21-4ab3-a34d-768916689874', 'b09378c1-4634-48f0-a6d7-fe4494998225', '撒上黑芝麻和葱花，再小火煎1-2分钟使底部更酥脆即可出锅。', 'active_cook', 5, 5);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('8ff2b0e8-c994-4ade-82bf-9e380f386911', 'user_test_123456', '金包银 (翡翠白菜卷)', '这是一道色香味俱全的家常菜。用鲜嫩的大白菜叶包裹着调味好的肉馅，经过蒸制后淋上鲜美的芡汁，口感清脆爽口，肉馅鲜嫩多汁。', 'recipes/42056707-8a93-41e0-a244-1c350a193401-jinbaoyin_1773001454002.png', '蒸锅, 炒锅', '晚餐', 'medium', 20, 15, '["中餐","猪肉","蒸菜","家常菜"]', '2025-10-19 10:58:15', '2025-10-19 10:58:15');
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('b75883bd-7a6a-48f7-a4ec-9f9d28b848bb', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '大白菜', 10, '叶', 0);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('30b59df9-e66e-47fd-9fa6-fcbc513b352c', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '猪肉馅', 250, '克', 1);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('44180655-7122-4a1c-91f9-76df11356141', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '香菇', 3, '朵', 2);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('446866b5-ac66-493b-8698-1d3e70744dd1', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '胡萝卜', 50, '克', 3);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('ba9eef35-d67b-42cf-90cb-b1f7e7ad9119', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '生抽', 1, '汤匙', 4);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('9602a9b7-ed6f-408b-8a81-113ab88c586d', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '蚝油', 1, '汤匙', 5);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('db0859b8-59ae-408d-9600-d492ea683c67', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '盐', 2, '克', 6);
