INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('a504dd86-67d4-40fe-b04d-a39a94e2ccfc', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '将猪肉馅加入葱姜末、生抽、盐、少许淀粉顺时针搅拌上劲。香菇和胡萝卜切碎拌入肉馅中。', 'prep', 10, 0);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('95e98fb7-e6ff-4941-8ea3-b1a6ec1d2612', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '大白菜叶洗净，入开水中烫软捞出，过凉水备用。', 'prep', 5, 1);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('f0ccb708-ed21-4eaa-b994-93fa26e77933', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '将白菜叶铺平，放上适量肉馅，由底部向上卷起，两边向内折叠，卷成圆柱形。', 'prep', 5, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('6a927e28-35c5-42af-8c6b-e65f77b7d28a', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '将卷好的白菜卷放入盘中，冷水上锅，大火蒸8-10分钟。', 'active_cook', 10, 3);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('7960cf25-e0e6-4328-887f-20e127911d04', '8ff2b0e8-c994-4ade-82bf-9e380f386911', '将蒸出的汤汁倒入锅中，加入蚝油和少许淀粉水勾薄芡，淋在白菜卷上即可。', 'active_cook', 5, 4);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('93b2232f-e3be-4c9c-9ce4-19b6b2837b00', 'user_test_123456', '蒜苔炒腊肉', '这是一道经典的家常小炒，蒜苔的爽脆与腊肉的咸香完美融合，下饭必备。', 'recipes/f41c467e-43a2-4a04-aa81-5e2f76f50eb2-suantai_larou_1773001490862.png', '炒锅', '晚餐', 'easy', 10, 10, '["中餐","家常菜","猪肉","蒜苔"]', '2025-12-11 14:18:10', '2025-12-11 14:18:10');
