INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('642bb858-ba5e-40fa-84e7-e87f139a8b31', 'user_test_123456', '干锅花菜', '一道经典的中式家常菜，花菜口感清脆，搭配五花肉的油脂香气和香辣的调料，非常下饭。', 'recipes/e5bae72e-f708-4fad-a1e2-a4c450c8cbc0-ganguo_huacai_1773001504027.png', '炒锅', '晚餐', 'easy', 10, 15, '["中餐","家常菜","香辣","蔬菜"]', '2025-10-21 13:29:41', '2025-10-21 13:29:41');
