INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('789fd911-cdae-4fe2-a49d-c62f928ef27a', '642bb858-ba5e-40fa-84e7-e87f139a8b31', '加入生抽调味，翻炒均匀后即可出锅。', 'active_cook', 2, 4);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('2c97b2de-3c2a-4eb9-9d28-b6f657be7725', 'user_test_123456', '皮蛋瘦肉粥', '经典的粤式粥品，以大米、皮蛋和瘦肉为主要原料，口感绵密滑顺，咸香鲜美，是极受欢迎的早餐或夜宵选择。', 'recipes/cefdb875-ea86-4c46-8906-93bccd715fe3-pidan_shourou_zhou_1773001517998.png', '砂锅或深汤锅', '早餐', 'easy', 15, 45, '["中餐","粤菜","粥品","猪肉"]', '2025-11-12 07:11:26', '2025-11-12 07:11:26');
