INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('aaff5646-6712-42de-a0b1-cba3ded9501f', '2c97b2de-3c2a-4eb9-9d28-b6f657be7725', '锅中加入约1.5升清水，大火烧开后下入浸泡好的大米，再次煮开后转小火慢熬，期间需间歇搅拌防止粘锅。', 'active_cook', 30, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('0c9639cc-8b24-4a5b-bfc8-c4efde399663', '2c97b2de-3c2a-4eb9-9d28-b6f657be7725', '待粥体变得粘稠时，下入皮蛋块和腌制好的肉丝，改中火煮约5-10分钟，直到肉色变白熟透。', 'active_cook', 10, 3);
