INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('3875178f-9f7b-43f5-ad5e-61f382e9ee2d', 'b24bc4ee-ec01-458d-a99d-1b130b67683a', '炒锅烧热，倒入食用油，下入蒜片爆香。', 'active_cook', 1, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('4351a505-a4bc-4a38-8799-b475e2dbed60', 'b24bc4ee-ec01-458d-a99d-1b130b67683a', '放入腌制好的鸡肉片，中火平铺在锅底，煎至两面金黄并熟透。', 'active_cook', 6, 3);
