INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('3db0a723-dbd5-48c4-bef9-e14788013ec1', 'user_test_123456', '酸辣土豆丝', '一道经典的家常菜，土豆丝口感清脆，酸辣适口，非常开胃。', 'recipes/6e71fcc9-723f-4b6d-89ac-c17727afd136-suanla_tudousi_1773001568550.png', '炒锅', '晚餐', 'easy', 10, 5, '["中餐","土豆","家常菜","酸辣"]', '2026-01-25 00:14:07', '2026-01-25 00:14:07');
