INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('691a5f47-8eb2-427d-a602-33e0073dad39', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '花椒', 10, '粒', 2);
