INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('91e41356-f681-453a-814c-2d7c822e88ff', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '盐', 1, '茶匙', 4);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('6428a6b6-70c0-43f2-bd15-0a8d60212437', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '大蒜', 2, '瓣', 5);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('be7d5d98-0909-4cea-8776-a69c859d1351', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '大葱', 1, '小段', 6);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('4c1122ca-17ea-44a2-aab4-24d271538591', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '食用油', 20, '毫升', 7);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('a8377eae-2f69-4bbb-adc8-9a85cb98669c', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '土豆去皮洗净，切成均匀的细丝，放入清水中浸泡，洗净表面淀粉以保持清脆。', 'prep', 5, 0);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('2275d6b5-8b62-4eb7-aa5f-0a32005ebb0d', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '干辣椒切段，葱切段，大蒜切片备用。', 'prep', 2, 1);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('f85b760f-31bc-49ad-94ef-fb16e11d1e9b', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '锅中倒入食用油，烧热后放入花椒，爆香后将花椒捞出不要。', 'active_cook', 1, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('9543b5db-8f62-4f8d-9532-867754466679', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '放入干辣椒段、葱段和蒜片爆香。', 'active_cook', 1, 3);
