INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('a31668e7-0acd-4afe-9671-2a00e75ec8bb', '3db0a723-dbd5-48c4-bef9-e14788013ec1', '加入白醋和盐，继续翻炒均匀后立即出锅，防止过度烹饪导致失去脆度。', 'active_cook', 1, 5);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('93502067-e3fc-445d-98cf-13f948347d54', 'user_test_123456', '老醋花生', '酥脆的花生米配上酸甜适口的陈醋汁，是一道经典的凉菜和佐酒小食。', 'recipes/8a1c470c-6be7-4b8e-87cb-f136904180b9-laocu_huasheng_1773001582260.png', '炒锅', '凉菜', 'easy', 5, 10, '["中餐","素食","下酒菜","经典"]', '2025-11-16 14:49:24', '2025-11-16 14:49:24');
