INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('bb15d15c-5324-4536-9e62-75e938d6fb4b', '93502067-e3fc-445d-98cf-13f948347d54', '生抽', 1, '勺', 3);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('2ef8eff9-1b82-4c32-816b-c1e3e2ef0d78', '93502067-e3fc-445d-98cf-13f948347d54', '洋葱', 30, '克', 4);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('bb4f4784-70a0-46af-bda5-0edda9d0e617', '93502067-e3fc-445d-98cf-13f948347d54', '食用油', 500, '毫升', 5);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('a84d431f-c0f0-4b6b-80bd-3a15ecd2a686', '93502067-e3fc-445d-98cf-13f948347d54', '洋葱切小丁备用；将陈醋、白糖、生抽调和成味汁。', 'prep', 3, 0);
