INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('d69cbe70-8c5c-4988-96f9-734eb6667b23', '93502067-e3fc-445d-98cf-13f948347d54', '将花生米摊开晾凉，保持酥脆感。', 'active_cook', 3, 3);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('fd5ed9c9-7187-48e0-9fd7-b36448c64536', '93502067-e3fc-445d-98cf-13f948347d54', '将凉透的花生米与味汁混合，撒上洋葱丁即可食用。', 'prep', 2, 4);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('329597be-9bab-4a6f-b0a2-fb4c6407bf34', 'user_test_123456', '辣椒炒肉', '辣椒炒肉是一道非常下饭的经典湘式家常菜，以猪肉和辣椒为主要食材，香辣可口，口感层次丰富。', 'recipes/0ca04be9-53b9-43dd-b9a8-e0943dc9a29d-lajiao_chaorou_1773001595086.png', '炒锅', '晚餐', 'easy', 10, 10, '["中餐","猪肉","家常菜","下饭菜","湘菜"]', '2026-02-21 17:54:07', '2026-02-21 17:54:07');
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('8d631ab4-7d40-4cab-98bc-e815920a6eb8', '329597be-9bab-4a6f-b0a2-fb4c6407bf34', '猪五花肉', 250, '克', 0);
