INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('1e1b38fc-d9a6-455c-97a5-0a803be75c0c', '329597be-9bab-4a6f-b0a2-fb4c6407bf34', '生抽', 1, '汤匙', 4);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('d9ffb9ab-e844-4553-a9fa-414840977d93', '329597be-9bab-4a6f-b0a2-fb4c6407bf34', '老抽', 0.5, '汤匙', 5);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('409f7098-3e46-47b2-a991-7aa61f709c11', '329597be-9bab-4a6f-b0a2-fb4c6407bf34', '蚝油', 1, '汤匙', 6);
