INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('77cc6abe-a1b6-4dba-881f-ec72a1d0de0f', '329597be-9bab-4a6f-b0a2-fb4c6407bf34', '猪五花肉洗净切薄片，辣椒去蒂切斜段，大蒜切片，生姜切丝备用。', 'prep', 5, 0);
