INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('5ad8d386-e7b9-4416-81f2-87a5921f89a6', '329597be-9bab-4a6f-b0a2-fb4c6407bf34', '锅中倒入适量底油，下入肉片中火煸炒至微微出油且变色。', 'active_cook', 2, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('fa5d8624-95b3-4f15-af7b-9b2f29b99f5f', '329597be-9bab-4a6f-b0a2-fb4c6407bf34', '放入姜丝和蒜片炒香，调入料酒、生抽、老抽翻炒均匀上色。', 'active_cook', 2, 3);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('9efe0520-eae5-4cdd-9792-6a468370d655', '329597be-9bab-4a6f-b0a2-fb4c6407bf34', '倒入煸好的辣椒，加入蚝油和盐，转大火快速翻炒均匀即可出锅。', 'active_cook', 3, 4);
INSERT INTO recipes (id, owner_user_id, title, description, cover_image, tools, category, difficulty, prep_time, cook_time, tags, created_at, last_modified_at) VALUES ('50a22757-9610-4a23-b6ee-d53ab483852c', 'user_test_123456', '意式萨拉米洋葱披萨', '这是一款色泽金黄、香脆可口的意式薄底披萨。选用咸香的萨拉米香肠搭配浓郁的马苏里拉芝士，点缀清甜的红洋葱丝和新鲜罗勒，风味丰富且平衡。', 'recipes/ff8cb4df-70a5-4c08-9fa2-9e6c14fc623e-yishi_salami_pisa_1773001608061.png', '烤箱, 披萨铲, 擀面杖, 烤盘', '晚餐', 'medium', 60, 15, '["西餐","烘焙","披萨","晚餐"]', '2025-12-13 04:15:33', '2025-12-13 04:15:33');
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('a726bcbf-8d8c-47f9-b5de-2362d9f01770', '50a22757-9610-4a23-b6ee-d53ab483852c', '高筋面粉', 250, '克', 0);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('35647f51-c447-4755-9e18-63374c973d20', '50a22757-9610-4a23-b6ee-d53ab483852c', '温水', 160, '毫升', 1);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('0c091fb4-5073-4ccf-8a32-d07c3beaee2f', '50a22757-9610-4a23-b6ee-d53ab483852c', '酵母', 3, '克', 2);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('0fd9baed-7188-48da-a11d-fd54fd03110f', '50a22757-9610-4a23-b6ee-d53ab483852c', '盐', 5, '克', 3);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('9fc60dc0-0446-4e47-bbff-f1c088832d84', '50a22757-9610-4a23-b6ee-d53ab483852c', '橄榄油', 10, '克', 4);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('5c512343-4d05-4fa8-90a6-0b210f825049', '50a22757-9610-4a23-b6ee-d53ab483852c', '马苏里拉芝士碎', 150, '克', 5);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('3e80ff45-3932-4737-a1f6-94f682461c29', '50a22757-9610-4a23-b6ee-d53ab483852c', '萨拉米香肠(Pepperoni)', 50, '克', 6);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('0b29cf63-b642-4469-91a0-bd6ef54d1f6b', '50a22757-9610-4a23-b6ee-d53ab483852c', '红洋葱丝', 20, '克', 7);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('7ef30a87-e90a-449e-a13e-eea1e1acf395', '50a22757-9610-4a23-b6ee-d53ab483852c', '披萨酱', 60, '克', 8);
INSERT INTO ingredients (id, recipe_id, name, amount, unit, sort_order) VALUES ('00a4fdc0-c20a-43d6-a697-bf71ef065d7e', '50a22757-9610-4a23-b6ee-d53ab483852c', '新鲜罗勒叶', 5, '克', 9);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('070ec251-51f7-484d-a69b-02e2f4000051', '50a22757-9610-4a23-b6ee-d53ab483852c', '将面粉、盐、酵母、水和橄榄油混合，揉搓成光滑且有弹性的面团。', 'prep', 15, 0);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('e318e30c-1cdc-45ed-9a2f-e3f7efb91c41', '50a22757-9610-4a23-b6ee-d53ab483852c', '面团放入涂油的盆中，盖上保鲜膜，在温暖处发酵约45分钟，直到体积加倍。', 'prep', 45, 1);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('2eb4a6c0-84ba-4b09-8ee5-02e9d109f700', '50a22757-9610-4a23-b6ee-d53ab483852c', '烤箱预热至230°C（或烤箱最高温）。', 'prep', 10, 2);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('0b313556-9e1f-47b6-9dd7-1407b7246adb', '50a22757-9610-4a23-b6ee-d53ab483852c', '将面团擀成圆形薄饼，边缘稍微留厚，涂上一层披萨酱。', 'active_cook', 5, 3);
INSERT INTO steps (id, recipe_id, description, step_type, time_minutes, sort_order) VALUES ('4755f603-5a12-4c9b-98bb-88efe4a05433', '50a22757-9610-4a23-b6ee-d53ab483852c', '均匀铺上芝士碎、萨拉米香肠片和薄洋葱丝。', 'active_cook', 5, 4);
